import java.util.*;

class Solution {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();

        for (int i = 0; i < n; i++) {
            String str = "";
            str += (" ".repeat(n - i - 1));
            for (int j = 0; j < 2 * i + 1; j++) {
                int val = (j > i) ? (3 * i + 1 - j) : (i + 1 + j);
                str += val;
            }
            System.out.println(str);
        }

        for (int i = n - 2; i >= 0; i--) {
            String str = "";

            str += (" ".repeat(n - i - 1));
            for (int j = 0; j < 2 * i + 1; j++) {
                int val = (j > i) ? (3 * i + 1 - j) : (i + 1 + j);
                str += val;
            }
            System.out.println(str);
        }
    }
}
